97	/// Read an env file and return the value for `key`, or None if the key is
98	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
99	/// and blank lines are skipped. The trailing newline is stripped from value.
100	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
101	    let content = std::fs::read_to_string(path).ok()?;
102	    let prefix = format!("{}=", key);
103	    for line in content.lines() {
104	        let trimmed = line.trim_start();
105	        if trimmed.starts_with('#') {
106	            continue;
107	        }
108	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
109	            return Some(rest.to_string());
110	        }
111	    }
112	    None
113	}
